                { q: "Excuse me, I have a traveler's check. Is it possible to ( ) here?", opts: ["caused it cashed", "got it cashing", "have it cashed", "made it cashing"], a: 2, explain: "The causative construction uses 'have + object + past participle' (have it cashed)." },
                { q: "Switzerland has lots of mountains, but they are now less densely equipped with skiers' dormitories than ( ).", opts: ["France and Austria", "of France and Austria", "that of France and Austria", "those of France and Austria"], a: 3, explain: "To avoid repeating the plural noun 'skiers' dormitories', the plural demonstrative pronoun 'those' is used ('those of France and Austria')." }
